const startButton=document.querySelector(".statusBar__button button"),allItems=document.querySelectorAll(".main__item"),statusText=document.querySelector(".statusBar__height__statusText");startButton.addEventListener("click",(t=>{let e=0,n=setInterval((()=>{allItems[e++].classList.add("animate"),e==allItems.length&&clearInterval(n)}),500)})),allItems.forEach((t=>{t.ontransitionstart=()=>{if("1"==t.innerText){const t="<div>------PROGRESS STARTED------</div>";statusText.insertAdjacentHTML("beforeend",t)}const e=function(t){return`<div>Status start ${t.innerText}</div>`}(t);statusText.insertAdjacentHTML("beforeend",e)},t.ontransitionend=()=>{const e=function(t){return`<div class="end${t.innerText}">Status end ${t.innerText}</div>`}(t);if(statusText.insertAdjacentHTML("beforeend",e),allItems.length==t.innerText){const t='<div">------PROGRESS ENDED------</div>';statusText.insertAdjacentHTML("beforeend",t),alert("success")}}}));